INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6e11b43e-moex-00462', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["私人之間亦得締結行政契約，惟須有法律授予私人享有公法上權利義務之處分權", "私人之間亦得締結行政契約，但並不能直接適用行政程序法有關行政契約之規定", "經授與公權力之私人，得與私人締結行政契約，此即屬私人間之行政契約的適例", "經授與公權力之私人，得與私人締結行政契約，此時該契約有行政程序法之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00463', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於陳情之敘述，下列何者錯誤？', '["陳情案雖未具住址者，機關仍應予以處理", "陳情得以言詞為之", "人民得以陳情為行政法令之查詢", "受理機關認為陳情無理由者，應通知當事人，並說明理由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00464', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '主管機關依檢驗結果，公告來自某些國家之進口肉品含有微量但未超標之飼料添加物，提醒民眾 注意。關於此項公告，下列敘述何者錯誤？', '["該公告係向民眾提供資訊之行為，屬於給付行政之一環", "依行政程序法規定，該公告為行政指導", "廠商如認為該公告之內容錯誤，致其權益受損，不得以訴願之方式請求撤銷", "廠商為避免商譽遭受重大損害，得聲請定暫時狀態處分，命主管機關於爭訟終結前更正公告內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00465', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '義務人依據行政執行法規定，對於具行政處分性質之執行命令聲明異議，依最高行政法院之法律 見解，此項異議程序之法律性質為何？', '["協議程序", "訴願前之先行程序", "相當於訴願程序", "督促程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00466', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何種情形，不適用行政程序法之程序規定？', '["甲不服行政機關駁回公務員迴避之申請，進而提請上級覆決", "外國人乙於其國內遭政治迫害，來我國申請政治難民之認定", "丙公務員與當事人為程序外接觸，雙方往來書面文件之處理", "焚化爐運轉許可於展延審查時，鄰近之居民丁申請程序參加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00467', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列法律規定之行政救濟程序，何者非屬相當訴願程序？', '["公務人員保障法之復審", "政府採購法之申訴", "教師法之再申訴", "集會遊行法之申復"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00468', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '某市之外環道路工程均已施工完畢，對地區發展及對外交通有莫大利益。惟行政法院受理原道路 土地所有權人所提起之撤銷訴訟後，發現原處分違法致原告的財產權受有損害，行政法院經斟酌 相關事由後，仍得駁回原告之訴。學理上稱此種判決為何？', '["撤銷判決", "中間判決", "情況判決", "給付判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00469', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬應以行政爭訟程序解決之爭議？', '["受刑人就不予假釋之決定，經向法務部提起復審，對復審結果仍表示不服", "林區管理處對於人民依據國有林地濫墾地補辦清理作業要點申請訂立租地契約未為准許之決定", "退役軍職人員與臺灣銀行訂立優惠存款契約後，由該契約衍生優惠存款利息給付爭議", "私立高中學生對於學校禁止其張貼海報，表示不服"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00470', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何種情況不得依行政訴訟法提起確認訴訟？', '["臨檢措施已執行完畢", "集會遊行驅離措施已執行完畢", "違建已被拆除完畢且無回復原狀之可能", "候選人因資格不符遭主管機關否准參選且該選舉已辦理完畢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00471', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於國家賠償法公共設施之國家賠償責任要件，下列敘述何者正確？', '["公共設施僅限人工構造物，山域、水域之自然公物不屬之", "於開放之山域、水域等自然公物內之設施，業經國家為適當之警告或標示者，國家即得不負損 害賠償責任", "私有公共設施供公眾使用，而國家處於事實上管理狀態者，亦適用國家賠償法", "公共設施未開放公用，人民擅自闖入致受損害，亦成立公共設施之國賠責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
